package main

import (
    "fmt"
    "net/http"
)

func hello(w http.ResponseWriter,
    r *http.Request) {
    fmt.Fprintf(w, "안녕, Go 서버! 🚀")
}

func main() {
    http.HandleFunc("/", hello)

    fmt.Println("서버 시작: :8080")
    http.ListenAndServe(":8080", nil)
}

// $ go run main.go
// 서버 시작: :8080
// $ curl localhost:8080
// 안녕, Go 서버! 🚀

func userHandler(w http.ResponseWriter,
    r *http.Request) {
    switch r.Method {
    case http.MethodGet:
        // 사용자 조회
        fmt.Fprintf(w, "사용자 목록")

    case http.MethodPost:
        // 사용자 생성
        fmt.Fprintf(w, "사용자 생성")

    default:
        w.WriteHeader(
            http.StatusMethodNotAllowed)
    }
}

func main() {
    http.HandleFunc("/users", userHandler)
    http.HandleFunc("/health", func(
        w http.ResponseWriter,
        r *http.Request) {
        w.Write([]byte("OK"))
    })
    http.ListenAndServe(":8080", nil)
}

type User struct {
    ID   int    `json:"id"`
    Name string `json:"name"`
    Age  int    `json:"age"`
}

func getUsers(w http.ResponseWriter,
    r *http.Request) {
    users := []User{
        {1, "고퍼", 10},
        {2, "도커", 8},
    }

    w.Header().Set("Content-Type",
        "application/json")
    w.WriteHeader(http.StatusOK)

    json.NewEncoder(w).Encode(users)
}
// 응답:
// [{"id":1,"name":"고퍼","age":10},
//  {"id":2,"name":"도커","age":8}]

func createUser(w http.ResponseWriter,
    r *http.Request) {
    if r.Method != http.MethodPost {
        http.Error(w, "POST만 허용",
            http.StatusMethodNotAllowed)
        return
    }

    var user User
    err := json.NewDecoder(
        r.Body).Decode(&user)
    if err != nil {
        http.Error(w, "잘못된 요청",
            http.StatusBadRequest)
        return
    }
    defer r.Body.Close()

    fmt.Fprintf(w, "생성됨: %s", user.Name)
}
// $ curl -X POST localhost:8080/users \
//   -d '{"name":"고퍼","age":10}'
// 생성됨: 고퍼

// 미들웨어 = 핸들러를 감싸는 함수
func Logger(next http.HandlerFunc) 
    http.HandlerFunc {
    return func(w http.ResponseWriter,
        r *http.Request) {
        start := time.Now()
        next(w, r)
        log.Printf("%s %s %v",
            r.Method, r.URL.Path,
            time.Since(start))
    }
}

func Auth(next http.HandlerFunc)
    http.HandlerFunc {
    return func(w http.ResponseWriter,
        r *http.Request) {
        token := r.Header.Get("Authorization")
        if token == "" {
            http.Error(w, "인증 필요", 401)
            return
        }
        next(w, r)
    }
}
// 체이닝: Auth(Logger(handler))
